// https://stackoverflow.com/questions/9781218/how-to-change-node-jss-console-font-color
import log from 'loglevel';

const FONT_RESET = '\x1b[0m';
const FONT_FG_BLACK = '\x1b[30m';
const FONT_BG_YELLOW = '\x1b[43m';

function format(entry: string) {
  return FONT_BG_YELLOW + FONT_FG_BLACK + entry + FONT_RESET;
}

export function logRequestAndAnswser(
  method: string,
  url: string,
  response: any,
) {
  const status: number = response.status;
  let location: string = response.headers.location;
  location = location ? '-> ' + location.split('?').shift() : '';
  url = url.split('?').shift() as string;
  log.debug(format(`${method} ${url} ${status} ${location}`));
}
